const today = new Date(); today.setHours(0,0,0,0);
const wk = new Date(today); wk.setDate(wk.getDate() + 7);
let outstanding = 0, overdue = 0, dueThisWeek = 0;
const debtors = {};
for (const it of $input.all()) {
  const inv = it.json;
  if (inv.Status !== 'AUTHORISED' || !(inv.AmountDue > 0)) continue;
  const due = new Date(inv.DueDateString); due.setHours(0,0,0,0);
  outstanding += inv.AmountDue;
  const name = inv.Contact?.Name || 'Unknown';
  debtors[name] = (debtors[name] || 0) + inv.AmountDue;
  if (due < today) overdue += inv.AmountDue;
  else if (due <= wk) dueThisWeek += inv.AmountDue;
}
const top = Object.entries(debtors).sort((a,b)=>b[1]-a[1]).slice(0,5)
  .map(([n,v]) => `${n}: ${v.toFixed(2)}`);
return [{ json: {
  outstanding: outstanding.toFixed(2), overdue: overdue.toFixed(2),
  dueThisWeek: dueThisWeek.toFixed(2), topDebtors: top.join('; ')
}}];

const s = $('Build summary').item.json;
const insight = $('Message a model').item.json.output?.[0]?.content?.[0]?.text || '';

const debtors = String(s.topDebtors).split(';').map(d => d.trim()).filter(Boolean).map(d => {
  const i = d.lastIndexOf(':');
  return { name: d.slice(0, i).trim(), amt: d.slice(i + 1).trim() };
});
const rows = debtors.map(d =>
  `<tr><td style="padding:6px 16px 6px 0;border-bottom:1px solid #eee;">${d.name}</td>
       <td style="padding:6px 0;text-align:right;font-weight:600;border-bottom:1px solid #eee;">$${d.amt}</td></tr>`
).join('');
const today = new Date().toLocaleDateString('en-US', { month:'long', day:'numeric', year:'numeric' });

const html = `
<div style="font-family:Arial,Helvetica,sans-serif;color:#1a1a1a;max-width:560px;margin:0 auto;padding:8px;">
  <h2 style="color:#0a8f5b;margin:0 0 2px;">Monday Cash-Flow Brief</h2>
  <p style="color:#888;margin:0 0 22px;font-size:13px;">Week of ${today}</p>

  <table style="width:100%;border-collapse:collapse;margin-bottom:26px;">
    <tr><td style="padding:12px;background:#f4f6f8;border-radius:6px;">Total outstanding</td>
        <td style="padding:12px;text-align:right;font-size:18px;font-weight:700;">$${s.outstanding}</td></tr>
    <tr><td style="padding:12px;color:#c0392b;">Overdue</td>
        <td style="padding:12px;text-align:right;font-size:18px;font-weight:700;color:#c0392b;">$${s.overdue}</td></tr>
    <tr><td style="padding:12px;">Expected in this week</td>
        <td style="padding:12px;text-align:right;font-size:18px;font-weight:700;">$${s.dueThisWeek}</td></tr>
  </table>

  <h3 style="margin:0 0 10px;">Top debtors to chase</h3>
  <table style="border-collapse:collapse;margin-bottom:24px;width:100%;">${rows}</table>

  <p style="background:#fff8e1;padding:12px 14px;border-left:3px solid #f5a623;border-radius:4px;margin:0 0 24px;">
    <strong>This week:</strong> ${insight}
  </p>

  <p style="color:#888;font-size:13px;margin:0;">— The Demo Company Accounts Team<br><em>Sent automatically by CashChaser</em></p>
</div>`;

return [{ json: { html } }];
